/* IVR call creatives (8kHz telephony audio, compressed to mp3) */
const AUDIO_B64_OPEN_APP = "";
const AUDIO_B64_CREATIVE_3 = "";


/* Sandboxed environments (incl. the desktop app) can block <audio> elements
   entirely, so we play through the Web Audio API instead: decode the base64
   to an AudioBuffer and drive playback with a custom player. */
function decodeB64(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}

const fmtTime = (s) => `${Math.floor(s / 60)}:${String(Math.floor(s % 60)).padStart(2, "0")}`;

function CallPlayer({ label, sub, b64 }) {
  const ctxRef = useRef(null);
  const bufRef = useRef(null);
  const srcRef = useRef(null);
  const startedAt = useRef(0);
  const offset = useRef(0);
  const rafRef = useRef(null);
  const endedNaturally = useRef(false);
  const [state, setState] = useState("idle"); // idle | loading | playing | paused | error
  const [pos, setPos] = useState(0);
  const [dur, setDur] = useState(0);

  const cleanup = () => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    if (srcRef.current) { try { srcRef.current.onended = null; srcRef.current.stop(); } catch (e) {} srcRef.current = null; }
  };
  useEffect(() => () => { cleanup(); if (ctxRef.current) ctxRef.current.close().catch(() => {}); }, []);

  const tick = () => {
    if (!ctxRef.current || !bufRef.current) return;
    const p = offset.current + (ctxRef.current.currentTime - startedAt.current);
    if (p >= bufRef.current.duration) return; // onended will finalize
    setPos(p);
    rafRef.current = requestAnimationFrame(tick);
  };

  const play = async () => {
    try {
      setState("loading");
      if (!ctxRef.current) {
        const AC = window.AudioContext || window.webkitAudioContext;
        ctxRef.current = new AC();
      }
      if (ctxRef.current.state === "suspended") await ctxRef.current.resume();
      if (!bufRef.current) {
        bufRef.current = await ctxRef.current.decodeAudioData(decodeB64(b64));
        setDur(bufRef.current.duration);
      }
      if (offset.current >= bufRef.current.duration) offset.current = 0;
      const src = ctxRef.current.createBufferSource();
      src.buffer = bufRef.current;
      src.connect(ctxRef.current.destination);
      endedNaturally.current = true;
      src.onended = () => {
        if (!endedNaturally.current) return;
        cleanup();
        offset.current = 0;
        setPos(0);
        setState("idle");
      };
      src.start(0, offset.current);
      startedAt.current = ctxRef.current.currentTime;
      srcRef.current = src;
      setState("playing");
      rafRef.current = requestAnimationFrame(tick);
    } catch (e) {
      console.error("Audio playback failed:", e);
      setState("error");
    }
  };

  const pause = () => {
    if (!srcRef.current) return;
    endedNaturally.current = false;
    offset.current += ctxRef.current.currentTime - startedAt.current;
    cleanup();
    setState("paused");
  };

  const playing = state === "playing";
  const progress = dur > 0 ? Math.min(pos / dur, 1) : 0;

  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 14, padding: "12px 14px",
      background: T.bg, borderRadius: 10, marginBottom: 10, flexWrap: "wrap",
    }}>
      <button
        onClick={playing ? pause : play}
        disabled={state === "loading" || state === "error"}
        aria-label={playing ? `Pause ${label}` : `Play ${label}`}
        style={{
          width: 42, height: 42, borderRadius: "50%", border: "none", flexShrink: 0,
          background: state === "error" ? T.line : T.red, color: "#fff",
          cursor: state === "error" ? "default" : "pointer",
          display: "flex", alignItems: "center", justifyContent: "center",
          boxShadow: state === "error" ? "none" : "0 2px 6px rgba(224,49,55,0.3)",
          fontSize: 15,
        }}>
        {state === "loading" ? (
          <span style={{ fontFamily: T.mono, fontSize: 9 }}>…</span>
        ) : playing ? (
          <svg width="13" height="14" viewBox="0 0 13 14"><rect x="1" y="1" width="4" height="12" rx="1" fill="#fff"/><rect x="8" y="1" width="4" height="12" rx="1" fill="#fff"/></svg>
        ) : (
          <svg width="14" height="14" viewBox="0 0 14 14"><path d="M3 1.5 L12 7 L3 12.5 Z" fill="#fff"/></svg>
        )}
      </button>
      <div style={{ flex: "1 1 220px", minWidth: 180 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
          <span style={{ fontFamily: T.body, fontSize: 13, fontWeight: 600, color: T.ink }}>{label}</span>
          <span style={{ fontFamily: T.mono, fontSize: 11, color: T.slate }}>
            {state === "error" ? "playback unavailable" : dur > 0 ? `${fmtTime(pos)} / ${fmtTime(dur)}` : sub}
          </span>
        </div>
        <div style={{ height: 6, background: T.line, borderRadius: 3, marginTop: 8, overflow: "hidden" }}>
          <div style={{
            height: "100%", width: `${progress * 100}%`, background: T.red,
            borderRadius: 3, transition: playing ? "none" : "width 200ms",
          }} />
        </div>
      </div>
    </div>
  );
}

